class Solution {
public:
    int maximumCostSubstring(string s, string chars, vector<int>& vals) {
        int maxCost = 0;
        for (int i = 0; i < s.size(); i++) {
            for (int j = i; j < s.size(); j++) {
                int cost = 0;
                for (int k = i; k <= j; k++) {
                    char c = s[k];
                    if (chars.find(c) != string::npos) {
                        cost += vals[chars.find(c)];
                    } else {
                        cost += c - 'a' + 1;
                    }
                }
                maxCost = max(maxCost, cost);
            }
        }
        return maxCost;
    }
};
